def reverse_words_preserving_spaces(s: str) -> str:
    # Extract words from the string
    words = []
    length = len(s)
    i = 0
    while i < length:
        if s[i] != ' ':
            start = i
            while i < length and s[i] != ' ':
                i += 1
            words.append(s[start:i])
        else:
            i += 1
    # Reverse the list of words
    words.reverse()
    # Rebuild the result string preserving space positions
    result_chars = []
    word_idx = 0
    char_idx = 0
    while char_idx < length:
        if s[char_idx] == ' ':
            result_chars.append(' ')
            char_idx += 1
        else:
            # Place the next word's characters
            word = words[word_idx]
            result_chars.extend(word)
            char_idx += len(word)
            word_idx += 1
    return ''.join(result_chars)

def are_anagrams(str1: str, str2: str) -> bool:
    # Remove all whitespace and convert to lowercase
    s1 = ''.join(str1.split()).lower()
    s2 = ''.join(str2.split()).lower()
    # Compare sorted characters
    return sorted(s1) == sorted(s2)

def run_length_encoding(s: str) -> str:
    if not s:
        return ""
    result = []
    count = 1
    prev = s[0]
    for char in s[1:]:
        if char == prev:
            count += 1
        else:
            result.append(str(count))
            result.append(prev)
            prev = char
            count = 1
    result.append(str(count))
    result.append(prev)
    return "".join(result)

def decode_run_length(encoded_str: str) -> str:
    decoded = []
    count_str = ''
    for ch in encoded_str:
        if ch.isdigit():
            count_str += ch
        else:
            count = int(count_str)
            decoded.append(ch * count)
            count_str = ''
    return ''.join(decoded)

def is_match(s: str, p: str) -> bool:
    # Dynamic programming approach
    m, n = len(s), len(p)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True

    # Deals with patterns like a*, a*b*, a*b*c* that can match empty string
    for j in range(2, n + 1):
        if p[j - 1] == '*':
            dp[0][j] = dp[0][j - 2]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if p[j - 1] == '*':
                # match zero occurrence of preceding element
                dp[i][j] = dp[i][j - 2]
                # match one or more if preceding element matches current char in s
                if p[j - 2] == s[i - 1] or p[j - 2] == '.':
                    dp[i][j] = dp[i][j] or dp[i - 1][j]
            else:
                if p[j - 1] == s[i - 1] or p[j - 1] == '.':
                    dp[i][j] = dp[i - 1][j - 1]
    return dp[m][n]

def string_permutations_unique(s: str) -> list[str]:
    def backtrack(path, counter, result):
        if len(path) == len(s):
            result.append(''.join(path))
            return
        for char in counter:
            if counter[char] > 0:
                path.append(char)
                counter[char] -= 1
                backtrack(path, counter, result)
                counter[char] += 1
                path.pop()

    counter = {}
    for char in s:
        counter[char] = counter.get(char, 0) + 1
    result = []
    backtrack([], counter, result)
    return result

def roman_to_int(s: str) -> int:
    values = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev_value = 0
    for char in reversed(s):
        value = values[char]
        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value
    return total

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    if not encode:
        shift = -shift
    result = []
    for char in text:
        if 'a' <= char <= 'z':
            offset = ord('a')
            shifted = (ord(char) - offset + shift) % 26 + offset
            result.append(chr(shifted))
        elif 'A' <= char <= 'Z':
            offset = ord('A')
            shifted = (ord(char) - offset + shift) % 26 + offset
            result.append(chr(shifted))
        else:
            result.append(char)
    return ''.join(result)

def min_window_substring(s: str, t: str) -> str:
    if not s or not t:
        return ""
    from collections import Counter

    dict_t = Counter(t)
    required = len(dict_t)

    # Left and Right pointer
    l, r = 0, 0

    # formed is how many unique characters in t are present in current window with desired frequency
    formed = 0

    window_counts = {}

    # (window length, left, right)
    ans = float('inf'), None, None

    while r < len(s):
        character = s[r]
        window_counts[character] = window_counts.get(character, 0) + 1

        if character in dict_t and window_counts[character] == dict_t[character]:
            formed += 1

        while l <= r and formed == required:
            character = s[l]

            # Save the smallest window until now
            if r - l + 1 < ans[0]:
                ans = (r - l + 1, l, r)

            window_counts[character] -= 1
            if character in dict_t and window_counts[character] < dict_t[character]:
                formed -= 1

            l += 1

        r += 1

    if ans[0] == float('inf'):
        return ""
    else:
        return s[ans[1]: ans[2] + 1]

def group_anagrams(strs: list[str]) -> list[list[str]]:
    anagram_map = {}
    for s in strs:
        key = ''.join(sorted(s))
        if key not in anagram_map:
            anagram_map[key] = []
        anagram_map[key].append(s)
    return list(anagram_map.values())

def is_balanced(s: str) -> bool:
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != pairs[char]:
                return False
            stack.pop()
        else:
            # Invalid character encountered
            return False
    return len(stack) == 0

