def multiply(num1: str, num2: str) -> str:
    if num1 == "0" or num2 == "0":
        return "0"
    m, n = len(num1), len(num2)
    result = [0] * (m + n)
    for i in range(m - 1, -1, -1):
        for j in range(n - 1, -1, -1):
            mul = (ord(num1[i]) - ord('0')) * (ord(num2[j]) - ord('0'))
            sum_ = mul + result[i + j + 1]
            result[i + j + 1] = sum_ % 10
            result[i + j] += sum_ // 10
    # Skip leading zeros
    idx = 0
    while idx < len(result) - 1 and result[idx] == 0:
        idx += 1
    return ''.join(str(x) for x in result[idx:])

def count_distinct_subsequences(text: str, pattern: str) -> int:
    m, n = len(text), len(pattern)
    # dp[i][j] = number of distinct subsequences of text[:i] equals pattern[:j]
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dp[i][0] = 1  # empty pattern is subsequence of any prefix
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if text[i - 1] == pattern[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][j]
    return dp[m][n]

def interleave_strings(s1: str, s2: str) -> str:
    result = []
