                dp[i][j] = dp[i - 1][j - 1]

    return dp[m][n]

def decode_base64(encoded: str) -> str:
    base64_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
    # Remove padding
    padding = encoded.count('=')
    encoded = encoded.rstrip('=')

    bits = ""
    for char in encoded:
        bits += f'{base64_chars.index(char):06b}'

    # Remove padding bits
    if padding:
        bits = bits[:-(padding * 2)]

    decoded_chars = []
    for i in range(0, len(bits), 8):
        byte = bits[i:i+8]
        if len(byte) < 8:
            break
        decoded_chars.append(chr(int(byte, 2)))

    return ''.join(decoded_chars)

def longest_substring_without_repeating_characters(s: str) -> int:
    char_index_map = {}
    left = 0
    max_length = 0
    for right, char in enumerate(s):
        if char in char_index_map and char_index_map[char] >= left:
            left = char_index_map[char] + 1
        char_index_map[char] = right
        max_length = max(max_length, right - left + 1)
    return max_length

def validate_ipv4_address(ip: str) -> bool:
    parts = ip.split('.')
    if len(parts) != 4:
        return False
    for part in parts:
        if not part.isdigit():
            return False
        if len(part) > 1 and part[0] == '0':
            return False
        num = int(part)
        if num < 0 or num > 255:
            return False
    return True

def merge(nums1: list[int], m: int, nums2: list[int], n: int) -> None:
    i = m - 1
    j = n - 1
    k = m + n - 1
    while i >= 0 and j >= 0:
        if nums1[i] > nums2[j]:
            nums1[k] = nums1[i]
            i -= 1
        else:
            nums1[k] = nums2[j]
            j -= 1
        k -= 1
    while j >= 0:
        nums1[k] = nums2[j]
        j -= 1
        k -= 1

