def minimum_spanning_tree_kruskal(edges: list[tuple[int, int, int]]) -> list[tuple[int, int, int]]:
    # Union-Find Data Structure
    parent = {}
    rank = {}

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(a, b):
        rootA = find(a)
        rootB = find(b)
        if rootA == rootB:
            return False
        if rank[rootA] < rank[rootB]:
            parent[rootA] = rootB
        elif rank[rootB] < rank[rootA]:
            parent[rootB] = rootA
        else:
            parent[rootB] = rootA
            rank[rootA] += 1
        return True

    # Initialize Union-Find
    nodes = set()
    for u, v, w in edges:
        nodes.add(u)
        nodes.add(v)
    for node in nodes:
        parent[node] = node
        rank[node] = 0

    # Sort edges by weight, then by node ids to break ties
    edges_sorted = sorted(edges, key=lambda x: (x[2], min(x[0], x[1]), max(x[0], x[1])))

    mst = []
    for u, v, w in edges_sorted:
        if union(u, v):
            # Store edges with smaller node first for consistency
            if u > v:
                u, v = v, u
            mst.append((u, v, w))

    # Sort final MST edges as per problem statement
    mst.sort(key=lambda x: (x[2], x[0], x[1]))
    return mst

