    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]
    return dist

def tarjan_scc(graph: dict) -> list:
    index = 0
    stack = []
    indices = {}
    lowlink = {}
    on_stack = set()
    sccs = []

    def strongconnect(node):
        nonlocal index
        indices[node] = index
        lowlink[node] = index
        index += 1
        stack.append(node)
        on_stack.add(node)

        for neighbor in graph.get(node, []):
            if neighbor not in indices:
                strongconnect(neighbor)
                lowlink[node] = min(lowlink[node], lowlink[neighbor])
            elif neighbor in on_stack:
                lowlink[node] = min(lowlink[node], indices[neighbor])

        if lowlink[node] == indices[node]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == node:
                    break
            sccs.append(sorted(scc))

    for node in graph:
        if node not in indices:
            strongconnect(node)

    return sorted(sccs, key=lambda c: c[0])

def find_cheapest_price(n: int, flights: list[tuple[int, int, int]], src: int, dst: int, k: int) -> int:
    # Bellman-Ford style dynamic programming approach
    prices = [float('inf')] * n
    prices[src] = 0
    for _ in range(k + 1):
        tmp_prices = prices.copy()
        for u, v, w in flights:
            if prices[u] == float('inf'):
                continue
            if prices[u] + w < tmp_prices[v]:
                tmp_prices[v] = prices[u] + w
        prices = tmp_prices
    return prices[dst] if prices[dst] != float('inf') else -1

