class UnionFind:
    def __init__(self, size: int):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, x: int) -> int:
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # Path compression
        return self.parent[x]

    def union(self, x: int, y: int) -> None:
        root_x = self.find(x)
        root_y = self.find(y)

        if root_x != root_y:
            if self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            elif self.rank[root_x] > self.rank[root_y]:
                self.parent[root_y] = root_x
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1

    def connected(self, x: int, y: int) -> bool:
        return self.find(x) == self.find(y)

def longest_path_in_dag(graph: dict) -> int:
    # Topological sort using DFS
    visited = set()
    stack = []

    def dfs(node):
        visited.add(node)
        for neighbor, _ in graph.get(node, []):
            if neighbor not in visited:
                dfs(neighbor)
        stack.append(node)

    for node in graph:
        if node not in visited:
            dfs(node)

    stack.reverse()  # topological order

    dist = {node: float('-inf') for node in graph}
    # If nodes have no incoming edges, they can start a path of length 0
    # Find nodes with no incoming edges
    incoming = {node: 0 for node in graph}
    for node in graph:
        for neighbor, _ in graph[node]:
            incoming[neighbor] = incoming.get(neighbor, 0) + 1
    for node in graph:
        if incoming.get(node, 0) == 0:
            dist[node] = 0

    for node in stack:
        if dist[node] != float('-inf'):
            for neighbor, weight in graph.get(node, []):
                if dist[neighbor] < dist[node] + weight:
                    dist[neighbor] = dist[node] + weight

    max_dist = max(dist.values()) if dist else 0
    return max_dist if max_dist != float('-inf') else 0

def solve_maze(maze: list[list[int]]) -> list[tuple[int, int]]:
    if not maze or not maze[0]:
        return []
    rows, cols = len(maze), len(maze[0])
    if maze[0][0] == 1 or maze[rows-1][cols-1] == 1:
        return []

    path = []
    visited = [[False]*cols for _ in range(rows)]

    def backtrack(r, c):
        if r < 0 or c < 0 or r >= rows or c >= cols:
            return False
        if maze[r][c] == 1 or visited[r][c]:
            return False
        path.append((r, c))
        visited[r][c] = True
        if r == rows - 1 and c == cols - 1:
            return True
        # Try all four directions
        if (backtrack(r + 1, c) or backtrack(r, c + 1) or backtrack(r - 1, c) or backtrack(r, c - 1)):
            return True
        # Backtrack
        path.pop()
        return False

    if backtrack(0, 0):
        return path
    return []

