    color = {}

    def is_valid(node, c):
        for neighbor in graph[node]:
            if neighbor in color and color[neighbor] == c:
                return False
        return True

    def backtrack(i):
        if i == len(nodes):
            return True
        node = nodes[i]
        for c in range(k):
            if is_valid(node, c):
                color[node] = c
                if backtrack(i + 1):
                    return True
                del color[node]
        return False

    return backtrack(0)

