def find_two_non_repeating_numbers(nums: list[int]) -> tuple[int, int]:
    xor_all = 0
    for num in nums:
        xor_all ^= num
    # Find rightmost set bit
    rightmost_set_bit = xor_all & (-xor_all)
    num1 = 0
    num2 = 0
    for num in nums:
        if num & rightmost_set_bit:
            num1 ^= num
        else:
            num2 ^= num
    return tuple(sorted((num1, num2)))

def power(x: float, n: int) -> float:
    if n == 0:
        return 1.0
    if n < 0:
        x = 1 / x
        n = -n
    result = 1.0
    current_product = x
    while n > 0:
        if n % 2 == 1:
            result *= current_product
        current_product *= current_product
        n //= 2
    return result

def integer_square_root(n: int) -> int:
    if n < 2:
        return n
    left, right = 1, n // 2
    while left <= right:
        mid = (left + right) // 2
        if mid * mid == n:
            return mid
        elif mid * mid < n:
            left = mid + 1
        else:
            right = mid - 1
    return right

def decimal_to_binary_string(n: int) -> str:
