import heapq

class MedianFinder:
    def __init__(self):
        # max heap for the smaller half
        self.small = []
        # min heap for the larger half
        self.large = []

    def add_num(self, num: int) -> None:
        # We push onto max heap (small) by pushing negative values
        if not self.small or num <= -self.small[0]:
            heapq.heappush(self.small, -num)
        else:
            heapq.heappush(self.large, num)

        # Balance heaps sizes (size difference at most 1)
        if len(self.small) > len(self.large) + 1:
            moved = -heapq.heappop(self.small)
            heapq.heappush(self.large, moved)
        elif len(self.large) > len(self.small):
            moved = heapq.heappop(self.large)
            heapq.heappush(self.small, -moved)

    def find_median(self) -> float:
        if len(self.small) > len(self.large):
            return float(-self.small[0])
        else:
            return (-self.small[0] + self.large[0]) / 2.0

