class PriorityQueue:
    def __init__(self):
        self.heap = []  # will store tuples of (-priority, value) to simulate max-heap

    def insert(self, value: int, priority: int) -> None:
        # Insert element as (-priority, value) to maintain max heap using Python's min-heap
        self.heap.append((-priority, value))
        self._sift_up(len(self.heap) - 1)

    def extract_max(self) -> int:
        if self.is_empty():
            raise IndexError("extract_max from empty priority queue")
        max_item = self.heap[0][1]
        last_item = self.heap.pop()
        if self.heap:
            self.heap[0] = last_item
            self._sift_down(0)
        return max_item

    def is_empty(self) -> bool:
        return len(self.heap) == 0

    def _sift_up(self, idx):
        parent = (idx - 1) // 2
        while idx > 0 and self.heap[idx] < self.heap[parent]:  # because we store negative priority
            self.heap[idx], self.heap[parent] = self.heap[parent], self.heap[idx]
            idx = parent
            parent = (idx - 1) // 2

    def _sift_down(self, idx):
        n = len(self.heap)
        while True:
            left = 2 * idx + 1
            right = 2 * idx + 2
            smallest = idx
            if left < n and self.heap[left] < self.heap[smallest]:
                smallest = left
            if right < n and self.heap[right] < self.heap[smallest]:
                smallest = right
            if smallest == idx:
                break
            self.heap[idx], self.heap[smallest] = self.heap[smallest], self.heap[idx]
            idx = smallest

