class NestedIterator:
    def __init__(self, nestedList: list):
        self.stack = []
        self._pushList(nestedList)

    def _pushList(self, nestedList):
        # Push elements in reverse order onto the stack
        for item in reversed(nestedList):
            self.stack.append(item)

    def next(self) -> int:
        if not self.hasNext():
            raise StopIteration
        return self.stack.pop()

    def hasNext(self) -> bool:
        while self.stack:
            top = self.stack[-1]
            if isinstance(top, int):
                return True
            self.stack.pop()
            self._pushList(top)
        return False

def evaluate_expression(expression: str) -> float:
    def precedence(op):
        if op in ('+', '-'):
            return 1
        if op in ('*', '/'):
            return 2
        return 0

    def apply_op(a, b, op):
        if op == '+':
            return a + b
        if op == '-':
            return a - b
        if op == '*':
            return a * b
        if op == '/':
            return a / b

    tokens = []
    i = 0
    n = len(expression)
    while i < n:
        if expression[i] == ' ':
            i += 1
            continue
        if expression[i] in '+-*/()':
            tokens.append(expression[i])
            i += 1
        else:
            num = 0
            while i < n and expression[i].isdigit():
                num = num * 10 + int(expression[i])
                i += 1
            tokens.append(num)

    values = []
    ops = []

    def process():
        b = values.pop()
        a = values.pop()
        op = ops.pop()
        values.append(apply_op(a, b, op))

    for token in tokens:
        if isinstance(token, int):
            values.append(float(token))
        elif token == '(': 
            ops.append(token)
        elif token == ')':
            while ops and ops[-1] != '(': 
                process()
            ops.pop()  # remove '('
        else:
            while ops and ops[-1] != '(' and precedence(ops[-1]) >= precedence(token):
                process()
            ops.append(token)

    while ops:
        process()

    return values[0]

