def implement_double_ended_queue() -> object:
    class Deque:
        def __init__(self):
            self.data = {}
            self.left_index = 0
            self.right_index = -1

        def append(self, value):
            self.right_index += 1
            self.data[self.right_index] = value

        def appendleft(self, value):
            self.left_index -= 1
            self.data[self.left_index] = value

        def pop(self):
            if self.is_empty():
                raise IndexError('pop from empty deque')
            val = self.data[self.right_index]
            del self.data[self.right_index]
            self.right_index -= 1
            return val

        def popleft(self):
            if self.is_empty():
                raise IndexError('pop from empty deque')
            val = self.data[self.left_index]
            del self.data[self.left_index]
            self.left_index += 1
            return val

        def is_empty(self):
            return self.right_index < self.left_index

        def size(self):
            return self.right_index - self.left_index + 1

    return Deque

