class BloomFilter:
    def __init__(self, m: int, k: int):
        self.m = m  # size of bit array
        self.k = k  # number of hash functions
        self.bit_array = [0] * m

    def _hashes(self, item: str):
        # Generate k hash values using built-in hash with salts
        for i in range(self.k):
            combined = str(i) + item
            # Use built-in hash and mod by m
            yield hash(combined) % self.m

    def add(self, item: str) -> None:
        for pos in self._hashes(item):
            self.bit_array[pos] = 1

    def possibly_contains(self, item: str) -> bool:
        return all(self.bit_array[pos] == 1 for pos in self._hashes(item))

