def reservoir_sampling(stream: iter, k: int) -> list:
    reservoir = []
    for i, item in enumerate(stream):
        if i < k:
            reservoir.append(item)
        else:
            j = random.randint(0, i)
            if j < k:
                reservoir[j] = item
    return reservoir

def convex_hull(points: list[tuple[int, int]]) -> list[tuple[int, int]]:
    # Remove duplicates
    points = list(set(points))
    if len(points) < 3:
        return sorted(points, key=lambda p: (p[1], p[0]))

    # Sort points by y, then x
    points.sort(key=lambda p: (p[1], p[0]))
    start = points[0]

    # Function to compute polar angle and distance from start
    def polar_angle(p):
        from math import atan2
        return atan2(p[1] - start[1], p[0] - start[0])

    def distance(p):
        return (p[0] - start[0]) ** 2 + (p[1] - start[1]) ** 2

    # Sort the points by polar angle and distance
    sorted_points = points[1:]
    sorted_points.sort(key=lambda p: (polar_angle(p), distance(p)))

    # Cross product to check orientation
    def cross(o, a, b):
        return (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])

    hull = [start, sorted_points[0]]

    for p in sorted_points[1:]:
        while len(hull) >= 2 and cross(hull[-2], hull[-1], p) <= 0:
            hull.pop()
        hull.append(p)

    return hull

def a_star_search(grid: list[list[int]], start: tuple[int, int], goal: tuple[int, int]) -> list[tuple[int, int]]:
    from heapq import heappush, heappop

    rows, cols = len(grid), len(grid[0]) if grid else 0

    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    if not (0 <= start[0] < rows and 0 <= start[1] < cols):
        return []
    if not (0 <= goal[0] < rows and 0 <= goal[1] < cols):
        return []
    if grid[start[0]][start[1]] == 1 or grid[goal[0]][goal[1]] == 1:
        return []

    open_set = []
    heappush(open_set, (heuristic(start, goal), 0, start))
    came_from = {}
    g_score = {start: 0}

    while open_set:
        _, current_g, current = heappop(open_set)

        if current == goal:
            path = []
            while current in came_from:
                path.append(current)
                current = came_from[current]
            path.append(start)
            return path[::-1]

        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            neighbor = (current[0] + dx, current[1] + dy)
            nr, nc = neighbor
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 0:
                tentative_g = current_g + 1
                if neighbor not in g_score or tentative_g < g_score[neighbor]:
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g
                    f_score = tentative_g + heuristic(neighbor, goal)
                    heappush(open_set, (f_score, tentative_g, neighbor))

    return []

def traveling_salesman(points: list[tuple[int, int]]) -> float:
    from math import sqrt
    n = len(points)
    if n == 0:
        return 0.0
    dist = [[0.0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            dx = points[i][0] - points[j][0]
            dy = points[i][1] - points[j][1]
            dist[i][j] = sqrt(dx*dx + dy*dy)

    ALL_VISITED = (1 << n) - 1
    memo = [[None]*(1 << n) for _ in range(n)]

    def dp(pos: int, mask: int) -> float:
        if mask == ALL_VISITED:
            return dist[pos][0]  # return to start
        if memo[pos][mask] is not None:
            return memo[pos][mask]
        ans = float('inf')
        for nxt in range(n):
            if (mask & (1 << nxt)) == 0:
                candidate = dist[pos][nxt] + dp(nxt, mask | (1 << nxt))
                if candidate < ans:
                    ans = candidate
        memo[pos][mask] = ans
        return ans

    return dp(0, 1 << 0)

def segment_tree(operations: list) -> list:
    # operations is a list of tuples, where the first element is the operation type:
    # 'build' with the array to build the tree
    # 'update' with index and new value
    # 'sum' with left and right indices
    # The function returns a list of results from 'sum' queries in order

    class SegmentTree:
        def __init__(self, data):
            self.n = len(data)
            self.size = 1
            while self.size < self.n:
                self.size <<= 1
            self.tree = [0] * (2 * self.size)
            # Build the tree
            for i in range(self.n):
                self.tree[self.size + i] = data[i]
            for i in range(self.size - 1, 0, -1):
                self.tree[i] = self.tree[2 * i] + self.tree[2 * i + 1]

        def update(self, idx, val):
            pos = self.size + idx
            self.tree[pos] = val
            pos //= 2
            while pos > 0:
                self.tree[pos] = self.tree[2 * pos] + self.tree[2 * pos + 1]
                pos //= 2

        def range_sum(self, l, r):
            l += self.size
            r += self.size
            s = 0
            while l <= r:
                if (l % 2) == 1:
                    s += self.tree[l]
                    l += 1
                if (r % 2) == 0:
                    s += self.tree[r]
                    r -= 1
                l //= 2
                r //= 2
            return s

    tree = None
    results = []
    for op in operations:
        if op[0] == 'build':
            tree = SegmentTree(op[1])
        elif op[0] == 'update':
            tree.update(op[1], op[2])
        elif op[0] == 'sum':
            results.append(tree.range_sum(op[1], op[2]))
    return results

def rabin_karp_search(text: str, pattern: str) -> list[int]:
    if pattern == "":
        return list(range(len(text) + 1))
    if len(pattern) > len(text):
        return []
    base = 256
    prime = 101
    m = len(pattern)
    n = len(text)

    pattern_hash = 0
    text_hash = 0
    h = 1

    # The value of h would be "pow(base, m-1) % prime"
    for i in range(m - 1):
        h = (h * base) % prime

    # Calculate the hash value of pattern and first window of text
    for i in range(m):
        pattern_hash = (base * pattern_hash + ord(pattern[i])) % prime
        text_hash = (base * text_hash + ord(text[i])) % prime

    results = []

    for i in range(n - m + 1):
        # Check the hash values of current window of text and pattern
        if pattern_hash == text_hash:
            # Check for characters one by one
            if text[i:i + m] == pattern:
                results.append(i)

        # Calculate hash value for next window of text: Remove leading digit, add trailing digit
        if i < n - m:
            text_hash = (base * (text_hash - ord(text[i]) * h) + ord(text[i + m])) % prime

            # We might get negative value of text_hash, convert it to positive
            if text_hash < 0:
                text_hash += prime

    return results

def find_maximum_xor(nums: list[int]) -> int:
    class TrieNode:
        def __init__(self):
            self.children = {}

    root = TrieNode()
    HIGH_BIT = 31  # since integers are non-negative, consider up to 31 bits

    def add(num):
        node = root
        for k in range(HIGH_BIT, -1, -1):
            bit = (num >> k) & 1
            if bit not in node.children:
                node.children[bit] = TrieNode()
            node = node.children[bit]

    def check(num):
        node = root
        xor_sum = 0
        for k in range(HIGH_BIT, -1, -1):
            bit = (num >> k) & 1
            toggled_bit = 1 - bit
            if toggled_bit in node.children:
                xor_sum = (xor_sum << 1) | 1
                node = node.children[toggled_bit]
            else:
                xor_sum = (xor_sum << 1) | 0
                node = node.children.get(bit, None)
                if node is None:
                    break
        return xor_sum

    max_xor = 0
    add(nums[0])
    for num in nums[1:]:
        max_xor = max(max_xor, check(num))
        add(num)
    return max_xor

