import random

class SkipListNode:
    def __init__(self, val, level):
        self.val = val
        self.forward = [None] * (level + 1)

class SkipList:
    MAX_LEVEL = 16
    P = 0.5

    def __init__(self):
        self.level = 0
        self.header = SkipListNode(-1, self.MAX_LEVEL)

    def random_level(self):
        lvl = 0
        while random.random() < self.P and lvl < self.MAX_LEVEL:
            lvl += 1
        return lvl

    def insert(self, val: int) -> None:
        update = [None] * (self.MAX_LEVEL + 1)
        current = self.header
        for i in reversed(range(self.level + 1)):
            while current.forward[i] and current.forward[i].val < val:
                current = current.forward[i]
            update[i] = current
        current = current.forward[0]
        if current is None or current.val != val:
            lvl = self.random_level()
            if lvl > self.level:
                for i in range(self.level + 1, lvl + 1):
                    update[i] = self.header
                self.level = lvl
            node = SkipListNode(val, lvl)
            for i in range(lvl + 1):
                node.forward[i] = update[i].forward[i]
                update[i].forward[i] = node

    def search(self, val: int) -> bool:
        current = self.header
        for i in reversed(range(self.level + 1)):
            while current.forward[i] and current.forward[i].val < val:
                current = current.forward[i]
        current = current.forward[0]
        return current is not None and current.val == val

    def delete(self, val: int) -> bool:
        update = [None] * (self.MAX_LEVEL + 1)
        current = self.header
        for i in reversed(range(self.level + 1)):
            while current.forward[i] and current.forward[i].val < val:
                current = current.forward[i]
            update[i] = current
        current = current.forward[0]
        if current is None or current.val != val:
            return False
        for i in range(self.level + 1):
            if update[i].forward[i] != current:
                break
            update[i].forward[i] = current.forward[i]
        while self.level > 0 and self.header.forward[self.level] is None:
            self.level -= 1
        return True

def job_scheduling(jobs: list[tuple[int, int, int]]) -> int:
    # Sort jobs by their end time
    jobs.sort(key=lambda x: x[1])
    n = len(jobs)
    # dp[i] will store the maximum profit by scheduling jobs[0..i]
    dp = [0] * n

    def binary_search(index):
        # Find the rightmost job which doesn't conflict with jobs[index]
        low, high = 0, index - 1
        while low <= high:
            mid = (low + high) // 2
            if jobs[mid][1] <= jobs[index][0]:
                if jobs[mid + 1][1] <= jobs[index][0]:
                    low = mid + 1
                else:
                    return mid
            else:
                high = mid - 1
        return -1

    for i in range(n):
        profit_including = jobs[i][2]
        l = binary_search(i)
        if l != -1:
            profit_including += dp[l]
        dp[i] = max(profit_including, dp[i - 1] if i > 0 else 0)

    return dp[-1] if n > 0 else 0
